$('#fileInput').addEventListener('change',async e=>{if(!requireWrite('Tu rol es de solo lectura. No se han incorporado documentos.')){e.target.value='';return}for(const file of e.target.files){let validation=await A365Security.validateFile(file);if(!validation.ok){toast(file.name+': '+validation.reason);await A365Security.log('Evidencia rechazada',{name:file.name,reason:validation.reason},'high');continue}let id='d'+Date.now()+Math.random().toString(16).slice(2),storageId=crypto.randomUUID(),storedName=storageId+'.a365e',ext=(file.name.split('.').pop()||'FILE').toUpperCase(),encrypted=await A365Crypto.encryptFile(file,storageId);let doc={id,storageId,storedName,encrypted:true,algorithm:'AES-256-GCM',integrityHash:encrypted.sha256,clientId:client().id,auditId:state.auditId,auditCode:audit().code,controlId:state.controlId,name:file.name,type:ext,mimeType:file.type,size:file.size,added:new Date().toISOString().slice(0,10),owner:db.settings.auditor,status:'En revisión',comment:'',folderPath:'Repositorio cifrado · '+storedName};db.documents.push(doc);await idbPut(storageId,encrypted);await A365Security.log('Evidencia incorporada',{auditId:state.auditId,controlId:state.controlId},'info')}save();e.target.value='';toast('Evidencias cifradas con AES-256-GCM');render()});
function selectAudit(id,destination='dashboard'){
  const a=allowedAudits().find(x=>x.id===id);
  if(!a){toast('No tienes permiso para acceder a esta auditoría');return}
  try{A365Auth.setContext(a.clientId,a.id)}catch(error){console.warn('No se pudo persistir el contexto autorizado',error)}
  state.auditId=a.id;
  state.clientId=a.clientId;
  const allFrameworks=[...(window.AUDITHUB_SEED?.frameworks||[]),...(db.frameworks||[])];
  const f=allFrameworks.find(x=>x.id===a.frameworkId);
  state.controlId=f?.sections?.[0]?.controls?.[0]?.[0]||'';
  state.tab='resumen';
  state.modal=null;
  state.view=destination;
  persistUiState();
  render();
}
