    img.onerror=()=>{tile.dataset.previewState='error';release();try{URL.revokeObjectURL(url)}catch{}galleryPreviewUrls.delete(url);if(fallback)fallback.innerHTML='No se pudo generar la miniatura<small>Pulsa para abrir el documento</small>'};
